// @ts-nocheck
const{ethers:ethers}=require("hardhat");async function main(){const[o]=await ethers.getSigners();console.log("Deploying with account:",o.address);const a=await ethers.getContractFactory("CampaignFactory"),e=await a.deploy();await e.waitForDeployment();const t=await e.getAddress(),n=await e.owner();console.log("CampaignFactory deployed to:",t),console.log("CampaignFactory owner:",n)}main().catch(o=>{console.error(o),process.exitCode=1});